#include <bits/stdc++.h>
using namespace std;
int n,a[50000007],len;
int main(){
	//cout<<sizeof(a)/1024/1024<<endl;
	cin>>n;
	len=n*2-1;
	for(int i=1;i<=n;i++){
		for(int j=1;j<=i*2-1;j++)
			a[j]+=(j<=i? j:i*2-j),a[j+1]+=a[j]/10,a[j]%=10;
		for(int j=i*2;j<=len;j++){
			if(a[j]<10)
				break;
			a[j+1]+=a[j]/10,a[j]%=10;
		}
		while(a[len+1])a[++len+1]+=a[len]/10,a[len]%=10;
	}
	/*for(int i=len;i;i--)
		cout<<a[i];
	cout<<endl;*/
	int x=0;
	for(int i=1;i<=len;i++){
		a[i]*=36;
		a[i]+=x;
		x=a[i]/10;
		a[i]%=10;
	}
	while(x){
		a[++len]+=x;
		x=a[len]/10;
		a[len]%=10;
	}
	for(int i=len;i;i--)
		cout<<a[i];
    return 0;
}
